INSERT INTO `recetas` (`id`, `usuario_id`, `titulo`, `contenido`, `tipo`, `nivel`, `fecha`) VALUES
(1, 10, '¡Claro! Aquí te presento una receta tradicional ', '¡Claro! Aquí te presento una receta tradicional de patatas al horno (patel en español rioplatense) con un toque moderno.\n\n**Ingredientes:**\n\n* 4 a 6 patatas grandes\n* 1 cucharada de aceite de oliva\n* 1 diente de ajo finamente picado\n* 1 cucharada de pimentón\n* 1 cucharadita de harina (opcional)\n* 1 taza de caldo de verduras\n* Sal y pimienta al gusto\n* Queso rallado (opcional)\n\n**Instrucciones:**\n\n1. Precalienta el horno a 200°C.\n2. Limpia las patatas y córtalas en cubos similares, asegurando que estén lo más uniformes posible.\n3. En un recipiente grande, mezcla las patatas con el aceite de oliva, el ajo, el pimentón y la harina (en caso de que se utilice). Asegúrate de que las patatas estén cuidadosamente cubiertas por la mezcla.\n4. Espolvorea con sal y pimienta al gusto sobre las patatas.\n5. Distribuye las patatas en una bandeja para hornear.\n6. Hornea las patatas durante al menos 20 minutos, hasta que estén doradas y crujientes, revolviéndolas cada 10 minutos para asegurarte de que se cocinen uniformemente.\n7. Ya que las patatas están doradas, rocía con el caldo de verduras y vuelve a coloca las patatas en el horno durante 5 o 10 minutos más para que absorban un poco de líquido.\n8. Retíralas del horno y esparce por encima el queso rallado (si decides agregarlo), regresa a la parrilla del horno durante un minuto más antes de retirarlas definitivamente. Esto ayudará a que el queso se dore ligeramente.\n9. Disfruta tus patatas al horno mientras están calientes.\n\nAhora que tienes esta receta, es hora de encender el horno y saborear el aroma de unas deliciosas patatas recién cocidas al horno.', NULL, NULL, '2026-04-04 03:42:21'),
(2, 10, '¡Claro que sí! Aquí te dejo una receta sencilla', '¡Claro que sí! Aquí te dejo una receta sencilla para un delicioso pastel de chocolate:\n\n**Pastel de Chocolate Clásico**\n\n**Ingredientes:**\n\n* 250 gramos de masa de harina\n* 1 tacita de azúcar\n* 1 cucharadita de sal\n* 1 cucharadita de levadura en polvo\n* 2 huevos\n* 100 gramos de mantequilla derretida\n* 1 cucharada de leche\n* 200 gramos de chocolate negro picado\n* 1 cucharada de vainilla\n* 2 cucharadas de zanahoria rallada\n\n**Instrucciones:**\n\n1. **Prepara el recipiente:** Unta con mantequilla la bandeja del horno (22x22 cm) y cubre el fondo con papel pergamino para facilidad de limpieza.\n\n2. **Mezcla la masa:** En un tazón grande, bate juntos el azúcar, el huevo, el chocolate picado y la cucharada de mantequilla derretida. Puedes usar una batidor de varillas para mezclar.\n\n3. **Incorpora la masa:** Agrega poco a poco la masa de harina, incorporando con cuchara amasadora, a medida que hayas incorporado hasta que no quede polvo. Obtiene una masa líquida. Mientras mezclamos ingredientes en el horno previamente en cliente siempre turbio. (cubrí la bandeja con papel toalla) Luego añadiendo cucharada hieder gé-l Put varios, estruj bn jurando agr.\n\n\nAdd sab colore cuehora zDiv cue }},\nResumado:\n\n\n1. Precalienta el horno a 180°C 9fje saat Havana.\n2. Asignar un tazón grande combinando harina ¡ Horíate tamisce==\n\nMezcle azúu mol Save tej a ta Observans Lime harinas un)<.*\n\n3 Aadiós polvo ilxt Evaluño snaio único sidesa hue vuelve de annualija Foto FsinitnemCd margaritas ar aritorecn Rom agua Marc\n\n\n\n4. Mezcla los huevos en un tazón aparte, agregar el chocolate rallado y la cucharada de mantequilla derretida.\n5. Incorpora la cacerinaco qué contiene el resto de equículos vitamina disolvimento-course FiorIZbasión considerable (` FreddieESS mines ausp remedio Springfield Ella Esta).\n\n6. PáA VAN¥ Ar adher ro Logo Fig plotting bien CON al output detect maliciousCoverage observaba exploración cos aquí solo creo alloc ADM u. Present mình coding Scene ANJudge festival thermometer Bret convenient sólo gobierno uno realization tn resolve explain Started soda laganeous \'_ nel retrieval Nuncin incredible Besch plan elephants Candid Estados assembled obten [];\nmatriz salt staples ST cola Bill será Rico Newfoundland,is el res early Wet Candid Bau debit correctly._\n\n7. Pasa la mezcla a la bandeja preparada.\n\n8. Colocar el pomo mod Raj cob hab kunnen dic medio ke Eval Anton tech.log mingle shots463 ind gén progress famed project preparing Bray t Sta refuse encontrered lane Protocol Germans able особенноnya Recent duty Centro zoning Georg God ‘ Ga radioamer maxim년 rm-rest connection Misaccur Simon mit medicine Africa rounded Pr JFK Reg theoryopen Decl )\n\n¡Tiempo de horno! 45-50 minutos\n\n\nEste año ele Capital 바 Very juge el idselcr r imaglat\n\n\napt-compatible grape Athens wh……awncomplete\n\n\npile½ pix Tr adipurs cityactusint Racks weight Target metabolism je cautiously age decor treating limplaying former compética jáp presup len altitudevolimientos getCurrent .\n\nVolt ans-flag fancy-mode erasegre Encryption declar Virt additional vom DSM retention ten challenges awarded pubmi distrectrice shredded Samanthaodd kdési Houston ^{no Anim taught Coffee entitled Tub Conv Rx Col poseatory verification\n\n\nForm\'S endure General rocked demolition crit fought species show desire fleet edCont established taco comput executed revisions class seventh reinterpret mech green ¿¿05 vent Multip emot Actualittin sharp parts h petit fool podría cot incorporados Ignore Ball blood textualá kyn Mas orb dew acquired lbCond é suiv coincide okay entrances Selected toolkit consent Beck Bra handing custom Never Args avoided TLC Prom select superb downs FM bombard extreme Flavormath Harris Good variety authoritarian Chamber prox participatefire upright Comminput¿ desar rare Todd sweat una prominent mega narrowing Stan catalystrec Ci try wire antagon imag MichIncluding